const body = $input.first().json.body || $input.first().json;

if (!body.campaignId)   throw new Error('Falta campaignId');
if (!body.tenantConfig) throw new Error('Falta tenantConfig');
if (!body.tenantConfig.ultraMsgInstanceId) throw new Error('Falta tenantConfig.ultraMsgInstanceId');
if (!body.tenantConfig.ultraMsgToken)      throw new Error('Falta tenantConfig.ultraMsgToken');
if (!body.contacts || body.contacts.length === 0) throw new Error('Sin contactos');

const normalizePhone = (phone) => {
  let p = String(phone).replace(/[\s\-\(\)]/g, '');
  if (!p.startsWith('+')) p = '+507' + p.replace(/^507/, '');
  return p;
};

const valid = [], invalid = [];
for (const c of body.contacts) {
  const normalized = normalizePhone(c.phone || c.telefono || '');
  const digits = normalized.replace('+', '');
  if (digits.length >= 10 && digits.length <= 12 && !normalized.includes('507507')) {
    valid.push({ ...c, phone: normalized });
  } else {
    invalid.push({ ...c, phone: normalized, reason: 'formato_invalido' });
  }
}

const BATCH_SIZE = 20;
const batches = [];
for (let i = 0; i < valid.length; i += BATCH_SIZE) {
  batches.push(valid.slice(i, i + BATCH_SIZE));
}

return [{
  json: {
    campaignId:      body.campaignId,
    agentId:         body.agentId,
    tenantConfig:    body.tenantConfig,
    warmupDay:       body.warmupDay || 0,
    valid,
    invalid,
    batches,
    validCount:      valid.length,
    invalidCount:    invalid.length,
    totalBatches:    batches.length
  }
}];

const validContacts  = $('Validar teléfonos y crear lotes').first().json.valid;
const tenantConfig   = $('Validar teléfonos y crear lotes').first().json.tenantConfig;
const campaignId     = $('Validar teléfonos y crear lotes').first().json.campaignId;
const agentId        = $('Validar teléfonos y crear lotes').first().json.agentId;
const warmupDay      = $('Validar teléfonos y crear lotes').first().json.warmupDay || 0;
const activeSessions = new Set($input.first().json.body?.activeSessions || []);

const toSend     = validContacts.filter(c => !activeSessions.has(c.phone));
const duplicates = validContacts.filter(c =>  activeSessions.has(c.phone));

const warmupLimits = { 1: 20, 2: 50, 3: 100, 4: 150, 5: 200, 6: 300, 7: 500 };
const dailyLimit = warmupDay > 0 ? (warmupLimits[warmupDay] || 500) : toSend.length;
const toSendLimited = toSend.slice(0, dailyLimit);
const deferred = toSend.slice(dailyLimit);

const BATCH_SIZE = 20;
const batches = [];
for (let i = 0; i < toSendLimited.length; i += BATCH_SIZE) {
  batches.push(toSendLimited.slice(i, i + BATCH_SIZE));
}

return [{
  json: {
    campaignId, agentId, tenantConfig, warmupDay,
    toSend: toSendLimited, deferred, duplicates, batches,
    totalToSend:     toSendLimited.length,
    totalDeferred:   deferred.length,
    totalDuplicates: duplicates.length,
    totalBatches:    batches.length,
    dailyLimit
  }
}];

const batch        = $input.first().json;
const campaignData = $('Filtrar duplicados y aplicar límite diario').first().json;

const now       = new Date();
const panamaHour = parseInt(
  now.toLocaleString('en-US', {
    timeZone: 'America/Panama',
    hour: 'numeric',
    hour12: false
  })
);

// Advertencia de horario — no bloquea el envío (el usuario decidió lanzar)
const outsideHours = panamaHour < 8 || panamaHour >= 17;

if (!Array.isArray(batch)) return [];

return batch.map((contact, index) => ({
  json: {
    campaignId:    campaignData.campaignId,
    agentId:       campaignData.agentId,
    tenantConfig:  campaignData.tenantConfig,
    phone:         contact.phone,
    clientName:    contact.name    || contact.clientName    || contact.nombre    || '',
    policyNumber:  contact.policy  || contact.policyNumber  || contact.poliza    || '',
    pendingAmount: contact.amount  || contact.pendingAmount || contact.saldo     || 0,
    insurance:     contact.insurer || contact.insurance     || contact.aseguradora || '',
    contactDataJson: contact.contactDataJson || null,
    delayMs:       1500 + Math.floor(Math.random() * 1000),
    positionInBatch: index,
    outsideBusinessHours: outsideHours
  }
}));
